values.value:
[
  {
    "name": "bodyFields",
    "type": "array",
    "required": false,
    "help": "List of body field API names to return (e.g., [\"Answer__c\", \"Question__c\"])",
    "label": "Body Fields"
  },
  {
    "name": "defaultIncludeBody",
    "type": "boolean",
    "required": false,
    "help": "Default value for includeBody parameter if not specified",
    "label": "Default Include Body"
  }
]

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "bodyFields": {
      "type": "array",
      "description": "List of body field API names to return (e.g., [\"Answer__c\", \"Question__c\"])"
    },
    "defaultIncludeBody": {
      "type": "boolean",
      "description": "Default value for includeBody parameter if not specified"
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "searchQuery": {
      "type": "string",
      "description": "Search query string for finding knowledge articles"
    },
    "articleId": {
      "type": "string",
      "description": "Specific Knowledge Article Version ID to retrieve",
      "format": "salesforce-id"
    },
    "language": {
      "type": "string",
      "description": "Language code for articles (e.g., en_US)"
    },
    "includeDrafts": {
      "type": "boolean",
      "description": "Include draft articles in search results"
    },
    "includeBody": {
      "type": "boolean",
      "description": "Include article body content in results"
    },
    "maxResults": {
      "type": "integer",
      "description": "Maximum number of articles to return",
      "minimum": 1,
      "maximum": 50
    }
  }
}
